var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"헉…… 헉……","JPN":"はぁ……はぁ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"제길……! 이 멍청한 것들!","JPN":"ちくしょう……！　このアホウども！","ENG":"Dammit...! Those idiots!","TWN":"該死……！沒用的東西！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"잘난 듯이 떠들어 놓고 이런 하찮은 함정에 빠진다고?","JPN":"偉そうな口をたたいておいて、こんなくだらない罠にかかるだと？","ENG":"Talking like they had everything under control, and they fall for the easiest trick in the book.","TWN":"在那邊一副多厲害的樣子，結果竟然掉到這種陷阱裡？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"펠릭스를 직접 만나야겠어. 유다 놈의 연구자료를 받아 내가 무녀를 완성시키는 거야.","JPN":"直接フェリックスに会わねば。ユダの研究資料を手に入れ、わしが巫女を完成させるのだ。","ENG":"I must go see Felix. I will take Judas' research and complete the priestess on my own.","TWN":"必須親自去找菲利克斯一趟，我要把尤達那傢伙的研究資料拿來，自己完成巫女！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그나마 마지막 협상수단은 남겨둬서 다행이군.","JPN":"それでも最後の交渉手段を残しておいたのは幸いじゃった。","ENG":"Fortunately, I still have leverage for one last negotiation.","TWN":"幸好我還有留一手。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"음……?","JPN":"うむ……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"이, 이게…… 어떻게 된 거지? 분명 이곳에 숨겨뒀을 텐데?","JPN":"こ、これは……どういうことだ？　確かにここに隠しておいたはずだが。","ENG":"W-where is it...? I am certain I hid it here...","TWN":"這，這……怎麼回事？我不是藏在這裡嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"다급해보이는군, 하바키.","JPN":"慌ててどうした、覇吐。","ENG":"What is the rush, Habaki?","TWN":"你看起來很慌張呢，幅木。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"유다……? 네놈이 왜 여기에……?","JPN":"ユダ……？　お前がなぜここにいる……？","ENG":"Judas? Why are you here...?","TWN":"尤達……？你怎麼在這裡……？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"날 미행한 건가?","JPN":"わしを尾行していたのか？","ENG":"Were you following me?","TWN":"你跟蹤我？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대가 찾고 있는 게 이 앰플인가?","JPN":"そなたが探しているのはこのアンプルか？","ENG":"This ample. Is this what you are looking for?","TWN":"你在找這個嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그…… 그걸 네가 어떻게 가지고 있는 거지?!","JPN":"そ……それをなぜお前が持っているのだ！？","ENG":"How… How do you have that?!","TWN":"那個……怎麼會在你那裡？！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"……역신의 피.","JPN":"……疫病神の血。","ENG":"...The blood of the Plague God.","TWN":"……瘟神血液。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"우리가 그대와 계약했을 때부터 줄곧 요구해왔던 물건이지.","JPN":"我らがそなたと契約した時からずっと要求してきたものだな。","ENG":"It is what I have been asking for from the start of our partnership.","TWN":"這是打從我們和你簽約時就一直要求的東西吧。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"네놈! 그걸 어떻게 나보다 먼저 찾아낸 거냐?","JPN":"貴様！　それをどうやってわしよりも先に探し出せた？","ENG":"How dare you! You looked for that before even thinking of trying to find me?!","TWN":"你！你怎麼會比我先找到？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"설마…… 예견을 이용한 건가?","JPN":"まさか……予言を利用したのか？","ENG":"Or... did you use foresight?","TWN":"難道你……利用預知的能力？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그렇소. 우리가 관측할 수 있는 건 확정된 미래.","JPN":"そうだ。我らが観測できるのは確定された未来。","ENG":"Yes. What we can perceive is the set future.","TWN":"沒錯，我們可以觀測到的是確定的未來。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};